function detectCounty(lat,lng){for(const[c,[a,b,d,e]]of Object.entries(COUNTY_BOUNDS)){if(lat>=a&&lat<=b&&lng>=d&&lng<=e)return c;}return null;}
function distanceMiles(a,b,c,d){const R=3958.8,dL=(c-a)*Math.PI/180,dG=(d-b)*Math.PI/180,x=Math.sin(dL/2)**2+Math.cos(a*Math.PI/180)*Math.cos(c*Math.PI/180)*Math.sin(dG/2)**2;return R*2*Math.atan2(Math.sqrt(x),Math.sqrt(1-x));}

